/**
 * All the node types included in the lezer syntax tree.
 * @internal
 */
export type FilterFieldLezerNodeType = 'Filter' | 'FilterGroup' | 'FilterStatement' | 'FilterKey' | 'Identifier' | 'FreeText' | 'EscapedStringCharacter' | 'Duration' | 'String' | 'IncompleteString' | 'Number' | 'Boolean' | 'ComparisonOperator' | 'InvalidComparisonOperator' | 'ExistsOperator' | 'SearchOperator' | 'PositionOperator' | 'InvalidPositionOperator' | 'FilterSimpleValue' | 'FilterIncludesValue' | 'InclusionOperator' | 'List' | 'LogicalOperator' | 'OpeningBracket' | 'ClosingBracket' | 'InvalidInclusionValue' | 'InvalidIdentifier' | '⚠' | 'ListValue' | 'Variable' | 'JsonPath' | 'JsonPathBase' | 'JsonPathIdentifier' | 'JsonPathArray' | 'JsonPathSquareOpeningBracket' | 'JsonPathNameSelector';
/**
 * Type to add the range prop defining any FilterField node.
 * @public
 */
export type FilterFieldNodeBase = {
    range: {
        from: number;
        to: number;
    };
};
/**
 * Type used for defining the FilterField root node.
 * @public
 */
export type FilterFieldRootNode = FilterFieldGroupNode & {
    version: string;
};
/**
 * Type used for defining a FilterField group node.
 * @public
 */
export type FilterFieldGroupNode = FilterFieldNodeBase & {
    type: 'Group';
    logicalOperator: 'AND' | 'OR';
    explicit: boolean;
    explicitLogicalOperator: boolean;
    children: FilterFieldNode[];
};
/**
 * Type used for defining a FilterField statement node.
 * @public
 */
export type FilterFieldStatementNode = FilterFieldNodeBase & {
    type: 'Statement';
    key?: FilterFieldKeyNode | FilterFieldJSONPathNode | (Omit<FilterFieldErrorNode, 'value'> & {
        value: string;
    });
    comparisonOperator?: FilterFieldLeafNode;
    value?: FilterFieldLeafNode | FilterFieldListNode;
};
/**
 * Type used for defining a FilterField key node.
 * @public
 */
export type FilterFieldKeyNode = FilterFieldNodeBase & {
    type: 'Key';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField JsonPath node.
 * @public
 */
export type FilterFieldJSONPathNode = FilterFieldNodeBase & {
    type: 'JSONPath';
    textValue: string;
    value: string;
    root: string;
    path: string;
};
/**
 * Type used for defining a FilterField string node.
 * @public
 */
export type FilterFieldStringNode = FilterFieldNodeBase & {
    type: 'String';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField IPAddress node.
 * @public
 */
export type FilterFieldIPAddressNode = FilterFieldNodeBase & {
    type: 'IPAddress';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField UID node.
 * @public
 */
export type FilterFieldUIDNode = FilterFieldNodeBase & {
    type: 'UID';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField SmartscapeId node.
 * @public
 */
export type FilterFieldSmartscapeIdNode = FilterFieldNodeBase & {
    type: 'SmartscapeId';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField Timestamp node.
 * @public
 */
export type FilterFieldTimestampNode = FilterFieldNodeBase & {
    type: 'Timestamp';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField variable node.
 * @public
 */
export type FilterFieldVariableNode = FilterFieldNodeBase & {
    type: 'Variable';
    variableType: 'Any';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField duration node.
 * @public
 */
export type FilterFieldDurationNode = FilterFieldNodeBase & {
    type: 'Duration';
    textValue: string;
    value?: number;
    unit?: 'ns' | 'ms' | 's' | 'm' | 'h' | 'd';
};
/**
 * Type used for defining a FilterField number node.
 * @public
 */
export type FilterFieldNumberNode = FilterFieldNodeBase & {
    type: 'Number';
    textValue: string;
    value: number;
};
/**
 * Type used for defining a FilterField BigInt node.
 * @public
 */
export type FilterFieldBigIntNode = FilterFieldNodeBase & {
    type: 'BigInt';
    textValue: string;
    value: string;
};
/**
 * Type used for defining a FilterField boolean node.
 * @public
 */
export type FilterFieldBooleanNode = FilterFieldNodeBase & {
    type: 'Boolean';
    textValue: string;
    value: boolean;
};
/**
 * Type used for defining a FilterField list node.
 * @public
 */
export type FilterFieldListNode = FilterFieldNodeBase & {
    type: 'List';
    textValue: string;
    value: FilterFieldLeafNode[];
};
/**
 * Type used for defining a FilterField comparison operator node.
 * @public
 */
export type FilterFieldComparisonOperatorNode = FilterFieldNodeBase & {
    type: 'ComparisonOperator';
    textValue: string;
    value: '=' | '!=' | '<' | '<=' | '>' | '>=' | 'starts-with' | 'ends-with' | 'contains' | 'not-starts-with' | 'not-ends-with' | 'not-contains' | 'matches-phrase' | 'not-matches-phrase';
};
/**
 * Type used for defining a FilterField exists operator node.
 * @public
 */
export type FilterFieldExistsOperatorNode = FilterFieldNodeBase & {
    type: 'ExistsOperator';
    textValue: string;
    value: boolean;
};
/**
 * Type used for defining a FilterField exists operator node.
 * @public
 */
export type FilterFieldSearchOperatorNode = FilterFieldNodeBase & {
    type: 'SearchOperator';
    textValue: '*~' | '* ~';
    value: 'search';
};
/**
 * Type used for defining a FilterField inclusion operator node.
 * @public
 */
export type FilterFieldInclusionOperatorNode = FilterFieldNodeBase & {
    type: 'InclusionOperator';
    textValue: 'in' | 'not in';
    value: 'in' | 'not in';
};
/**
 * Type used for defining a FilterField error node.
 * @public
 */
export type FilterFieldErrorNode = FilterFieldNodeBase & {
    type: 'Error';
    textValue: string;
    value: string | FilterFieldLeafNode[];
};
/**
 * Type used for defining a FilterField leaf node.
 * @public
 */
export type FilterFieldLeafNode = FilterFieldKeyNode | FilterFieldJSONPathNode | FilterFieldStringNode | FilterFieldVariableNode | FilterFieldNumberNode | FilterFieldBigIntNode | FilterFieldBooleanNode | FilterFieldDurationNode | FilterFieldIPAddressNode | FilterFieldUIDNode | FilterFieldSmartscapeIdNode | FilterFieldTimestampNode | FilterFieldComparisonOperatorNode | FilterFieldExistsOperatorNode | FilterFieldSearchOperatorNode | FilterFieldInclusionOperatorNode | FilterFieldErrorNode;
/**
 * Type used for defining a FilterField value node.
 * @public
 */
export type FilterFieldValueNode = FilterFieldLeafNode | FilterFieldListNode;
/**
 * Type used for defining a FilterField node.
 * @public
 */
export type FilterFieldNode = FilterFieldGroupNode | FilterFieldStatementNode | FilterFieldListNode | FilterFieldLeafNode;
/**
 * Type used for defining the FilterField syntax tree.
 * @public
 */
export type FilterFieldTree = FilterFieldRootNode | undefined;
/** @internal */
export type FilterFieldStatementTokenType = Exclude<keyof FilterFieldStatementNode, 'range' | 'type'>;
